// =============================
// Build System Message
// Mode: Run Once for Each Item
// =============================

// SelecionaAgent
const agentNode = $('SelecionaAgent').first()?.json || {};
const systemPrompt = (agentNode.system_prompt || '').trim();

// Governance (vem do item atual)
const gov = $json || {};

// Canal
const channel = 'whatsapp';

// FunÃ§Ã£o segura para JSON
function safeParse(value) {
  if (!value) return [];
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch {
      return [];
    }
  }
  return value;
}

// =============================
// Build governance compact text
// =============================

const parts = [];

// PLAYBOOK
if (gov.playbook_name && gov.playbook_name !== 'default') {
  parts.push(
    'PLAYBOOK: ' +
      gov.playbook_name +
      ' (canal: ' +
      (gov.playbook_channel || channel) +
      ')'
  );

  if (gov.playbook_description)
    parts.push(gov.playbook_description);

  if (gov.behavior_source)
    parts.push('Modo: ' + gov.behavior_source);

  parts.push('');
}

// RULES
const rules = safeParse(gov.rules);
if (Array.isArray(rules) && rules.length) {
  parts.push('=== REGRAS ===');
  rules.forEach((r, i) => {
    parts.push(
      (r.rule_order || i + 1) +
        '. [' +
        (r.rule_type || 'policy') +
        '] ' +
        (r.instruction || r.title || '')
    );
  });
  parts.push('');
}

// TABLES
const tables = safeParse(gov.tables);
if (Array.isArray(tables) && tables.length) {
  parts.push('=== TABELAS AUTORIZADAS ===');
  tables.forEach(t => {
    parts.push(
      '- ' +
        t.table_name +
        ' (' +
        (t.access_mode || 'read') +
        '): ' +
        (t.purpose || '')
    );
  });
  parts.push('');
}

// STATES
const states = safeParse(gov.states);
if (Array.isArray(states) && states.length) {
  parts.push('=== ESTADOS DA CONVERSA ===');
  states.forEach(s => {
    const label = s.state_label || s.state_key || '';
    const markers = [];
    if (s.is_initial) markers.push('INICIAL');
    if (s.is_terminal) markers.push('TERMINAL');

    parts.push(
      '- ' +
        label +
        (markers.length ? ' [' + markers.join(', ') + ']' : '')
    );
  });
  parts.push('');
}

// HANDOFF
const handoff = safeParse(gov.handoff);
if (Array.isArray(handoff) && handoff.length) {
  parts.push('=== HANDOFF (encaminhamento humano) ===');
  handoff.forEach(h => {
    parts.push(
      '- ' +
        (h.from_channel || '?') +
        ' â†’ ' +
        (h.to_channel || '?') +
        ' (trigger: ' +
        (h.trigger_type || 'manual') +
        ')'
    );

    if (h.pause_bot_while_operator)
      parts.push('  Bot pausa enquanto operador atende');

    if (h.operator_can_return_to_bot)
      parts.push('  Operador pode devolver ao bot');
  });
  parts.push('');
}

// Junta governanÃ§a
const governanceCompact = parts.join('\n');

// =============================
// Final system message
// =============================

const finalParts = [];

if (systemPrompt) finalParts.push(systemPrompt);

if (governanceCompact) {
  finalParts.push(
    '\n\n--- REGRAS DO PLAYBOOK (canal: ' +
      channel +
      ') ---\n' +
      governanceCompact
  );
}

const finalSystemMessage =
  finalParts.join('') ||
  'Responda em portuguÃªs brasileiro. Seja educado e profissional.';

return {
  json: {
    finalSystemMessage
  }
};
